def onCook(scriptOp):
	scriptOp.clear()
	if not hasattr(parent.Lister, 'ColDefine') or not parent.Lister.ColDefine:
		return
	cols = [c.val for c in parent.Lister.ColDefine.row("column")[1:]]
	if parent().AutoHeaderRows:
		scriptOp.appendRow(cols + 
				(['sourceIndex'] if parent.Lister.par.Sourceindexinoutput.eval() 
						else []))
	for d in parent.Lister.Data[parent().AutoHeaderRows:]:
		row = ['' if d[c] is None else d[c] for c in cols if c in d]
		if parent.Lister.par.Sourceindexinoutput.eval():
			try:
				row.append(d['sourceIndex'])
			except:
				raise
		scriptOp.appendRow(row)
	#scriptOp.copy(scriptOp.inputs[0])	# no need to call .clear() above when copying
	#scriptOp.insertRow(['color', 'size', 'shape'], 0)
	#scriptOp.appendRow(['red', '3', 'square'])
