	loggerExt = ext.LoggerExt

	try:
		while not loggerExt.LogQueue.empty():
			record = loggerExt.QueueListener.dequeue(False)
			loggerExt.QueueListener.handle(record)

	except loggerExt.LogQueue.Empty as e:
		print(e)
		return

	except (TypeError, IndexError):
		# Handle multiple exceptions in a single block
		print("Type or Index error occurred.")

