def onValueChange(par, prev):
	# use par.eval() to get current value
	if hasattr(ext.SignalingClientExt, 'on'+par.name+'Change'):
		getattr(ext.SignalingClientExt, 'on'+par.name+'Change')(par)
	return

# Called at end of frame with complete list of individual parameter changes.
# The changes are a list of named tuples, where each tuple is (Par, previous value)
def onValuesChanged(changes):
	for c in changes:
		# use par.eval() to get current value
		par = c.par
		prev = c.prev
	return

def onPulse(par):
	if par.name == 'Reset':
		ext.SignalingClientExt.Reset()
	elif hasattr(ext.SignalingClientExt, 'on'+par.name+'Pulse'):
		getattr(ext.SignalingClientExt, 'on'+par.name+'Pulse')(par)	
	return

